content:
{
  "sentences": [
    {
      "text": "因為我忘記帶鑰匙，所以進不了家門。",
      "pinyin": "Yīnwèi wǒ wàngjì dài yàoshi, suǒyǐ jìn bù liǎo jiā mén.",
      "pinyin_numeric": "yin1 wei4 wo3 wang4 ji4 dai4 yao4 shi5, suo3 yi3 jin4 bu4 liao3 jia1 men2.",
      "translation_en": "Because I forgot to bring my keys, I couldn't get into the house.",
      "translation_ko": "열쇠를 가져오는 것을 잊어버려서 집에 들어갈 수 없었어요."
    },
    {
      "text": "因為昨天颱風，所以今天學校停課。",
      "pinyin": "Yīnwèi zuótiān táifēng, suǒyǐ jīntiān xuéxiào tíng kè.",
      "pinyin_numeric": "yin1 wei4 zuo2 tian1 tai2 feng1, suo3 yi3 jin1 tian1 xue2 xiao4 ting2 ke4.",
      "translation_en": "Because there was a typhoon yesterday, school is canceled today.",
      "translation_ko": "어제 태풍이 와서 오늘 학교가 휴교예요."
    },
    {
      "text": "因為他生病了，所以沒有來上班。",
      "pinyin": "Yīnwèi tā shēngbìng le, suǒyǐ méiyǒu lái shàngbān.",
      "pinyin_numeric": "yin1 wei4 ta1 sheng1 bing4 le5, suo3 yi3 mei2 you3 lai2 shang4 ban1.",
      "translation_en": "Because he got sick, he didn't come to work.",
      "translation_ko": "그가 아파서 출근하지 않았어요."
    },
    {
      "text": "因為路上塞車，所以我遲到了。",
      "pinyin": "Yīnwèi lù shàng sāichē, suǒyǐ wǒ chídào le.",
      "pinyin_numeric": "yin1 wei4 lu4 shang4 sai1 che1, suo3 yi3 wo3 chi2 dao4 le5.",
      "translation_en": "Because there was a traffic jam on the road, I was late.",
      "translation_ko": "길이 막혀서 지각했어요."
    },
    {
      "text": "因為手機壞掉了，所以我換了一隻新的。",
      "pinyin": "Yīnwèi shǒujī huài diào le, suǒyǐ wǒ huàn le yī zhī xīn de.",
      "pinyin_numeric": "yin1 wei4 shou3 ji1 huai4 diao4 le5, suo3 yi3 wo3 huan4 le5 yi1 zhi1 xin1 de5.",
      "translation_en": "Because my phone broke, I replaced it with a new one.",
      "translation_ko": "휴대폰이 고장 나서 새것으로 바꿨어요."
    },
    {
      "text": "因為他弄丟了我的書，所以他賠了我一本。",
      "pinyin": "Yīnwèi tā nòng diū le wǒ de shū, suǒyǐ tā péi le wǒ yī běn.",
      "pinyin_numeric": "yin1 wei4 ta1 nong4 diu1 le5 wo3 de5 shu1, suo3 yi3 ta1 pei2 le5 wo3 yi1 ben3.",
      "translation_en": "Because he lost my book, he compensated me with one.",
      "translation_ko": "그가 제 책을 잃어버려서 한 권을 배상했어요."
    },
    {
      "text": "因為突然下雨，所以我們沒有去公園。",
      "pinyin": "Yīnwèi túrán xiàyǔ, suǒyǐ wǒmen méiyǒu qù gōngyuán.",
      "pinyin_numeric": "yin1 wei4 tu2 ran2 xia4 yu3, suo3 yi3 wo3 men5 mei2 you3 qu4 gong1 yuan2.",
      "translation_en": "Because it suddenly rained, we didn't go to the park.",
      "translation_ko": "갑자기 비가 와서 공원에 가지 않았어요."
    },
    {
      "text": "因為他感冒了，所以頭很痛。",
      "pinyin": "Yīnwèi tā gǎnmào le, suǒyǐ tóu hěn tòng.",
      "pinyin_numeric": "yin1 wei4 ta1 gan3 mao4 le5, suo3 yi3 tou2 hen3 tong4.",
      "translation_en": "Because he caught a cold, his head hurts a lot.",
      "translation_ko": "그가 감기에 걸려서 머리가 많이 아파요."
    },
    {
      "text": "因為我們吵架了，所以結果很不開心。",
      "pinyin": "Yīnwèi wǒmen chǎojià le, suǒyǐ jiéguǒ hěn bù kāixīn.",
      "pinyin_numeric": "yin1 wei4 wo3 men5 chao3 jia4 le5, suo3 yi3 jie2 guo3 hen3 bu4 kai1 xin1.",
      "translation_en": "Because we had a quarrel, the result was very unhappy.",
      "translation_ko": "우리가 싸워서 결과가 매우 불행했어요."
    },
    {
      "text": "因為他誤會了我，所以他跟我道歉了。",
      "pinyin": "Yīnwèi tā wùhuì le wǒ, suǒyǐ tā gēn wǒ dàoqiàn le.",
      "pinyin_numeric": "yin1 wei4 ta1 wu4 hui4 le5 wo3, suo3 yi3 ta1 gen1 wo3 dao4 qian4 le5.",
      "translation_en": "Because he misunderstood me, he apologized to me.",
      "translation_ko": "그가 저를 오해해서 사과했어요."
    }
  ]
}
